local function send_json_response(status, data)
    ngx.status = status
    ngx.header["Content-Type"] = "application/json; charset=utf-8"
    ngx.say(cjson.encode(data))
    return ngx.exit(status)
end

local function connect_redis()
    local red, err = redis:new()
    if not red then
        return nil, "Failed to create Redis instance: " .. (err or "unknown")
    end

    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "Failed to connect to Redis at " .. REDIS_HOST .. ":" .. REDIS_PORT .. " - " .. (err or "unknown")
    end

    if REDIS_PASSWORD and REDIS_PASSWORD ~= "" then
        local ok, err = red:auth(REDIS_PASSWORD)
        if not ok then
            return nil, "Redis authentication failed: " .. (err or "unknown")
        end
    end

    return red, nil
end

local function release_redis(red)
    if not red then
        return
    end
    local ok, err = red:set_keepalive(REDIS_KEEPALIVE_TIMEOUT, REDIS_KEEPALIVE_POOL_SIZE)
    if not ok then
        ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
    end
end

local function parse_request_body()
    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    if not body then
        return nil, "Empty request body"
    end

    local ok, data = pcall(cjson.decode, body)
    if not ok then
        return nil, "Invalid JSON in request body"
    end

    return data, nil
end

local function validate_command(cmd)
    if not cmd or type(cmd) ~= "string" or cmd == "" then
        return false, "Command must be a non-empty string"
    end

    local lower_cmd = string.lower(cmd)

    if BLOCKED_COMMANDS[lower_cmd] then
        return false, "Command '" .. cmd .. "' is blocked for security reasons"
    end

    if not ALLOWED_COMMANDS[lower_cmd] then
        return false, "Command '" .. cmd .. "' is not in the allowed commands list"
    end

    return true, nil
end

local function format_redis_result(result)
    if type(result) == "table" then
        -- Check if it's a Redis null bulk reply
        local formatted = {}
        for i, v in ipairs(result) do
            if v == ngx.null then
                formatted[i] = cjson.null
            elseif type(v) == "table" then
                formatted[i] = format_redis_result(v)
            else
                formatted[i] = v
            end
        end
        return formatted
    elseif result == ngx.null then
        return cjson.null
    else
        return result
    end
end

local function execute_command(red, cmd, args)
    local lower_cmd = string.lower(cmd)

    -- For eval command, handle specially
    if lower_cmd == "eval" or lower_cmd == "evalsha" then
        if not args or #args < 2 then
            return nil, "eval/evalsha requires at least script/sha and numkeys arguments"
        end

        local script = args[1]
        local numkeys = tonumber(args[2])
        if not numkeys then
            return nil, "Second argument (numkeys) must be a number"
        end

        -- Build the eval arguments
        local eval_args = {}
        for i = 3, #args do
            eval_args[#eval_args + 1] = args[i]
        end

        if lower_cmd == "eval" then
            local result, err = red:eval(script, numkeys, unpack(eval_args))
            return result, err
        else
            local result, err = red:evalsha(script, numkeys, unpack(eval_args))
            return result, err
        end
    end

    -- Generic command execution
    local redis_func = red[lower_cmd]
    if not redis_func then
        return nil, "Redis command method '" .. lower_cmd .. "' not found"
    end

    local result, err
    if args and #args > 0 then
        result, err = redis_func(red, unpack(args))
    else
        result, err = redis_func(red)
    end

    return result, err
end

local function handle_single_command()
    local method = ngx.req.get_method()

    local cmd, args, db

    if method == "GET" then
        -- Parse from query parameters
        local uri_args = ngx.req.get_uri_args()
        cmd = uri_args["cmd"] or uri_args["command"]
        db = tonumber(uri_args["db"])

        -- Args can be passed as repeated 'arg' parameters or as 'args' JSON array
        local raw_args = uri_args["arg"]
        local json_args = uri_args["args"]

        if json_args then
            local ok, parsed = pcall(cjson.decode, json_args)
            if ok and type(parsed) == "table" then
                args = parsed
            else
                return send_json_response(400, {
                    success = false,
                    error = "Invalid JSON in 'args' parameter"
                })
            end
        elseif raw_args then
            if type(raw_args) == "table" then
                args = raw_args
            else
                args = { raw_args }
            end
        else
            args = {}
        end

    elseif method == "POST" then
        local data, err = parse_request_body()
        if not data then
            return send_json_response(400, {
                success = false,
                error = err
            })
        end

        cmd = data.cmd or data.command
        args = data.args or data.arguments or {}
        db = tonumber(data.db)

        if type(args) ~= "table" then
            args = { args }
        end
    else
        return send_json_response(405, {
            success = false,
            error = "Method not allowed. Use GET or POST."
        })
    end

    -- Validate command
    local valid, err = validate_command(cmd)
    if not valid then
        return send_json_response(400, {
            success = false,
            error = err
        })
    end

    -- Connect to Redis
    local red, err = connect_redis()
    if not red then
        return send_json_response(500, {
            success = false,
            error = err
        })
    end

    -- Select database if specified
    if db and db >= 0 then
        local ok, err = red:select(db)
        if not ok then
            release_redis(red)
            return send_json_response(500, {
                success = false,
                error = "Failed to select database " .. db .. ": " .. (err or "unknown")
            })
        end
    end

    -- Execute command
    local result, err = execute_command(red, cmd, args)
    release_redis(red)

    if err then
        return send_json_response(500, {
            success = false,
            error = "Redis command failed: " .. (err or "unknown"),
            command = cmd,
            args = args
        })
    end

    local formatted_result = format_redis_result(result)

    return send_json_response(200, {
        success = true,
        result = formatted_result,
        command = cmd,
        args = args
    })
end

local function handle_pipeline()
    if ngx.req.get_method() ~= "POST" then
        return send_json_response(405, {
            success = false,
            error = "Pipeline endpoint only accepts POST requests"
        })
    end

    local data, err = parse_request_body()
    if not data then
        return send_json_response(400, {
            success = false,
            error = err
        })
    end

    local commands = data.commands
    if not commands or type(commands) ~= "table" or #commands == 0 then
        return send_json_response(400, {
            success = false,
            error = "Request must contain a non-empty 'commands' array"
        })
    end

    -- Validate max pipeline size
    local MAX_PIPELINE_SIZE = 100
    if #commands > MAX_PIPELINE_SIZE then
        return send_json_response(400, {
            success = false,
            error = "Pipeline size exceeds maximum of " .. MAX_PIPELINE_SIZE .. " commands"
        })
    end

    -- Validate all commands first
    for i, cmd_entry in ipairs(commands) do
        local cmd = cmd_entry.cmd or cmd_entry.command
        local valid, err = validate_command(cmd)
        if not valid then
            return send_json_response(400, {
                success = false,
                error = "Command #" .. i .. ": " .. err
            })
        end
    end

    -- Connect to Redis
    local red, err = connect_redis()
    if not red then
        return send_json_response(500, {
            success = false,
            error = err
        })
    end

    -- Select database if specified
    local db = tonumber(data.db)
    if db and db >= 0 then
        local ok, err = red:select(db)
        if not ok then
            release_redis(red)
            return send_json_response(500, {
                success = false,
                error = "Failed to select database " .. db .. ": " .. (err or "unknown")
            })
        end
    end

    -- Initialize pipeline
    red:init_pipeline()

    -- Queue all commands
    for _, cmd_entry in ipairs(commands) do
        local cmd = string.lower(cmd_entry.cmd or cmd_entry.command)
        local args = cmd_entry.args or cmd_entry.arguments or {}

        if type(args) ~= "table" then
            args = { args }
        end

        local redis_func = red[cmd]
        if redis_func then
            if #args > 0 then
                redis_func(red, unpack(args))
            else
                redis_func(red)
            end
        end
    end

    -- Execute pipeline
    local results, err = red:commit_pipeline()
    release_redis(red)

    if not results then
        return send_json_response(500, {
            success = false,
            error = "Pipeline execution failed: " .. (err or "unknown")
        })
    end

    -- Format results
    local formatted_results = {}
    for i, result in ipairs(results) do
        local cmd_entry = commands[i]
        local cmd_name = cmd_entry.cmd or cmd_entry.command or "unknown"

        if type(result) == "table" and result[1] == false then
            formatted_results[i] = {
                success = false,
                command = cmd_name,
                error = tostring(result[2])
            }
        else
            formatted_results[i] = {
                success = true,
                command = cmd_name,
                result = format_redis_result(result)
            }
        end
    end

    return send_json_response(200, {
        success = true,
        results = formatted_results,
        count = #formatted_results
    })
end

